     1→import React, { useRef, useState } from "react";
     2→import ReCAPTCHA from "react-google-recaptcha";
     3→import { useNavigate } from "react-router-dom";
     4→
     5→const captchaKey = import.meta.env.VITE_CAPTCHA_KEY;
     6→const captchaSecret = import.meta.env.VITE_CAPTCHA_SECRET;
     7→const serverlUrl = import.meta.env.VITE_SERVER_URL;
     8→
     9→export default function SignUpForm({ registerUser }) {
    10→  const [formValue, setFormValue] = useState({
    11→    email: "",
    12→    fullname: "",
    13→    password: "",
    14→    repeatPassword: "",
    15→  });
    16→  const [errorValue, setErrorValue] = useState({});
    17→  const [userExists, setUserExists] = useState(undefined);
    18→  const [loading, setLoading] = useState(false);
    19→  const [captchaError, setCaptchaError] = useState(false);
    20→  const navigate = useNavigate();
    21→  const captchaRef = useRef();
    22→
    23→  const submitForm = async (e) => {
    24→    e.preventDefault();
    25→    setLoading(true);
    26→    setErrorValue(validateForm(formValue));
    27→    if (Object.keys(validateForm(formValue)).length > 0) {
    28→      setLoading(false);
    29→      return null;
    30→    } else {
    31→      let captchaToken = captchaRef.current?.getValue();
    32→      if (captchaToken.length === 0) {
    33→        setCaptchaError("ReCaptcha is mandatory");
    34→        setLoading(false);
    35→        return;
    36→      }
    37→      window.scrollTo(0, 0);
    38→      const verify = await verifyCaptcha(captchaToken);
    39→      captchaRef.current?.reset();
    40→
    41→      if (verify) {
    42→        const registerationSuccess = await registerUser(formValue);
    43→        setFormValue({
    44→          email: "",
    45→          fullname: "",
    46→          password: "",
    47→          repeatPassword: "",
    48→        });
    49→        if (registerationSuccess) {
    50→          setLoading(false);
    51→          setUserExists(false);
    52→          navigate("/sign-in");
    53→          window.scrollTo(0, 0);
    54→        } else {
    55→          setLoading(false);
    56→          setUserExists(true);
    57→        }
    58→      } else {
    59→        setFormValue({
    60→          firstname: "",
    61→          lastname: "",
    62→          email: "",
    63→          message: "",
    64→        });
    65→        setCaptchaError("");
    66→        setLoading(false);
    67→      }
    68→    }
    69→  };
    70→
    71→  const handleForm = (e) => {
    72→    const { name, value } = e.target;
    73→    setFormValue({ ...formValue, [name]: value });
    74→  };
    75→
    76→  const verifyCaptcha = async (captchaToken) => {
    77→    try {
    78→      const response = await fetch(serverlUrl, {
    79→        method: "POST",
    80→        body: JSON.stringify({
    81→          secret: captchaSecret,
    82→          captchaToken,
    83→        }),
    84→        headers: {
    85→          "Content-Type": "application/json",
    86→        },
    87→      });
    88→      if (response.status === 200) {
    89→        return true;
    90→      } else {
    91→        return false;
    92→      }
    93→    } catch (error) {
    94→      console.error("Could not verify captcha!", error.message);
    95→      return false;
    96→    }
    97→  };
    98→  const validateForm = (value) => {
    99→    const errors = {};
   100→    const emailRegex = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
   101→    const numberRegex = /\d/;
   102→    if (!value.email) {
   103→      errors.email = "Enter the email";
   104→    } else if (!emailRegex.test(value.email)) {
   105→      errors.email = "The email is not valid";
   106→    }
   107→    if (!value.password) {
   108→      errors.password = "Password field is required";
   109→    }
   110→    if (!value.repeatPassword) {
   111→      errors.repeatPassword = "Password field is required";
   112→    }
   113→    if (value.password.length < 8 && value.password) {
   114→      errors.password = "Password must be min. 8 characters";
   115→    }
   116→    if (value.repeatPassword < 8 && value.repeatPassword) {
   117→      errors.repeatPassword = "Password must be min. 8 characters";
   118→    } else if (
   119→      value.password &&
   120→      value.repeatPassword &&
   121→      value.password !== value.repeatPassword
   122→    ) {
   123→      errors.password = "Passwords don't match";
   124→      errors.repeatPassword = "Passwords don't match";
   125→    }
   126→    if (!value.fullname) {
   127→      errors.fullname = "Enter your name";
   128→    } else if (value.fullname.length < 4 && value.fullname) {
   129→      errors.fullname = "Enter a valid name";
   130→    } else if (numberRegex.test(value.fullname)) {
   131→      errors.fullname = "Please enter a valid name";
   132→    }
   133→
   134→    return errors;
   135→  };
   136→
   137→  return (
   138→    <React.Fragment>
   139→      {loading ? (
   140→        <div role="status" className="flex flex-col gap-4 items-center">
   141→          <p className="text-indigo-400 text-xl">Almost there...</p>
   142→          <svg
   143→            aria-hidden="true"
   144→            className="w-10 h-10 mt-6 text-gray-200 animate-spin dark:text-gray-600 fill-indigo-400"
   145→            viewBox="0 0 100 101"
   146→            fill="none"
   147→            xmlns="http://www.w3.org/2000/svg">
   148→            <path
   149→              d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z"
   150→              fill="currentColor"
   151→            />
   152→            <path
   153→              d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z"
   154→              fill="currentFill"
   155→            />
   156→          </svg>
   157→        </div>
   158→      ) : (
   159→        <form onSubmit={submitForm} className="mt-8 space-y-6">
   160→          {userExists !== undefined && userExists ? (
   161→            <span className="text-red-400">
   162→              A user with such email already exists
   163→            </span>
   164→          ) : null}
   165→          <section>
   166→            <label htmlFor="fullname" className="sr-only">
   167→              Full name
   168→            </label>
   169→            <input
   170→              onChange={handleForm}
   171→              value={formValue.fullname}
   172→              id="fullname"
   173→              name="fullname"
   174→              type="text"
   175→              autoComplete="full-name"
   176→              className="appearance-none rounded-none relative block w-full px-3 py-2 border border-gray-300 placeholder-gray-500 text-white rounded-t-md focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
   177→              placeholder="Full name"
   178→            />
